mapper.select:
SELECT COUNT(*)
FROM noti_policy
WHERE np_event_cd = #{eventCd}

mapper.insert:
INSERT INTO noti_policy (
    np_event_cd
  , np_biz_nm
  , np_receiver_user_type
  , np_title_tpl
  , np_body_tpl
  , np_link_tpl
  , np_use_yn
) VALUES (
    #{npEventCd}
  , #{npBizNm}
  , #{npReceiverUserType}
  , #{npTitleTpl}
  , #{npBodyTpl}
  , #{npLinkTpl}
  , #{npUseYn}
)

mapper.update:
UPDATE noti_policy
SET
    np_biz_nm = #{npBizNm}
  , np_receiver_user_type = #{npReceiverUserType}
  , np_title_tpl = #{npTitleTpl}
  , np_body_tpl = #{npBodyTpl}
  , np_link_tpl = #{npLinkTpl}
  , np_use_yn = #{npUseYn}
WHERE np_event_cd = #{npEventCd}

UPDATE noti_policy
SET np_use_yn = #{useYn}
WHERE np_event_cd = #{eventCd}
